const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIO(server);

const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

const SESSION_TIMEOUT = 30 * 60 * 1000;
const MAX_SCORE_INCREMENT = 1000;
const SCORE_RATE_LIMIT = 5000;

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function generateSecureHash(username, sessionToken, timestamp) {
  const secret = process.env.GAME_SECRET || crypto.randomBytes(32).toString('hex');
  return crypto
    .createHmac('sha256', secret)
    .update(`${username}:${sessionToken}:${timestamp}`)
    .digest('hex');
}

function validateSession(sessionToken) {
  const session = sessions.get(sessionToken);
  if (!session) return null;
  
  if (Date.now() - session.createdAt > SESSION_TIMEOUT) {
    sessions.delete(sessionToken);
    return null;
  }
  
  session.lastActivity = Date.now();
  return session;
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const sanitized = username.trim().substring(0, 20);
  if (sanitized.length < 3) return null;
  if (!/^[a-zA-Z0-9_-]+$/.test(sanitized)) return null;
  return sanitized;
}

function validateScore(score, previousScore, timestamp, lastScoreUpdate) {
  if (typeof score !== 'number' || !Number.isFinite(score)) return false;
  if (score < 0 || score > 1000000) return false;
  
  if (previousScore !== undefined) {
    const scoreDiff = score - previousScore;
    if (scoreDiff < 0) return false;
    if (scoreDiff > MAX_SCORE_INCREMENT) return false;
    
    const timeDiff = timestamp - lastScoreUpdate;
    if (timeDiff < SCORE_RATE_LIMIT) return false;
  }
  
  return true;
}

io.use((socket, next) => {
  const sessionToken = socket.handshake.auth.sessionToken;
  
  if (!sessionToken) {
    return next(new Error('Authentication required'));
  }
  
  const session = validateSession(sessionToken);
  if (!session) {
    return next(new Error('Invalid or expired session'));
  }
  
  socket.sessionToken = sessionToken;
  socket.username = session.username;
  next();
});

io.on('connection', (socket) => {
  console.log(`Player connected: ${socket.username}`);
  
  const playerData = {
    username: socket.username,
    sessionToken: socket.sessionToken,
    socketId: socket.id,
    score: 0,
    lastScoreUpdate: Date.now(),
    connectedAt: Date.now()
  };
  
  players.set(socket.id, playerData);
  
  socket.emit('authenticated', {
    username: socket.username,
    sessionToken: socket.sessionToken
  });
  
  socket.emit('leaderboard', Array.from(leaderboard.values()).sort((a, b) => b.score - a.score).slice(0, 10));
  
  socket.on('authenticate', (data) => {
    socket.emit('error', { message: 'Already authenticated' });
  });
  
  socket.on('updateScore', (data) => {
    const session = validateSession(socket.sessionToken);
    if (!session) {
      socket.emit('error', { message: 'Session expired' });
      socket.disconnect(true);
      return;
    }
    
    const player = players.get(socket.id);
    if (!player) {
      socket.emit('error', { message: 'Player not found' });
      return;
    }
    
    const { score, timestamp, hash } = data;
    
    if (!timestamp || Math.abs(Date.now() - timestamp) > 10000) {
      socket.emit('error', { message: 'Invalid timestamp' });
      return;
    }
    
    const expectedHash = generateSecureHash(player.username, socket.sessionToken, timestamp);
    if (hash !== expectedHash) {
      socket.emit('error', { message: 'Invalid score signature' });
      socket.disconnect(true);
      return;
    }
    
    if (!validateScore(score, player.score, timestamp, player.lastScoreUpdate)) {
      socket.emit('error', { message: 'Invalid score update' });
      return;
    }
    
    player.score = score;
    player.lastScoreUpdate = timestamp;
    
    leaderboard.set(player.username, {
      username: player.username,
      score: player.score
    });
    
    socket.emit('scoreUpdated', { score: player.score });
    
    io.emit('leaderboard', Array.from(leaderboard.values()).sort((a, b) => b.score - a.score).slice(0, 10));
  });
  
  socket.on('getLeaderboard', () => {
    socket.emit('leaderboard', Array.from(leaderboard.values()).sort((a, b) => b.score - a.score).slice(0, 10));
  });
  
  socket.on('disconnect', () => {
    console.log(`Player disconnected: ${socket.username}`);
    players.delete(socket.id);
  });
});

app.use(express.json());

app.post('/api/login', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  
  if (!username) {
    return res.status(400).json({ error: 'Invalid username' });
  }
  
  const sessionToken = generateSessionToken();
  const timestamp = Date.now();
  
  const session = {
    username,
    sessionToken,
    createdAt: timestamp,
    lastActivity: timestamp
  };
  
  sessions.set(sessionToken, session);
  
  const hash = generateSecureHash(username, sessionToken, timestamp);
  
  res.json({
    sessionToken,
    username,
    timestamp,
    hash
  });
});

app.post('/api/logout', (req, res) => {
  const { sessionToken } = req.body;
  
  if (sessionToken) {
    sessions.delete(sessionToken);
  }
  
  res.json({ success: true });
});

app.get('/api/leaderboard', (req, res) => {
  const top = Array.from(leaderboard.values())
    .sort((a, b) => b.score - a.score)
    .slice(0, 10);
  
  res.json(top);
});

setInterval(() => {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (now - session.lastActivity > SESSION_TIMEOUT) {
      sessions.delete(token);
    }
  }
}, 60000);

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});